  return new Promise(function(resolve) {
    var body = JSON.stringify({ model: 'gpt-4o', messages: messages, max_tokens: 2048, temperature: temperature || 1 });
    var req = https.request({ hostname: 'oai-dax-dakona-pilot.openai.azure.com', path: '/openai/deployments/gpt-4o/chat/completions?api-version=2024-08-01-preview', method: 'POST', headers: { 'api-key': '635645200b2c4f90a1833de2bda6b753', 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) } }, function(res) { var data = ''; res.on('data', function(c) { data += c; }); res.on('end', function() { try { resolve(JSON.parse(data).choices[0].message.content || ''); } catch(e) { resolve(''); } }); }); req.on('error', function() { resolve(''); }); req.write(body); req.end();
  });
}
var lines = inputBrief.split('\n'); var intro = []; var headingBlocks = []; var currentBlock = null;
for (var i = 0; i < lines.length; i++) { var line = lines[i]; if (line.match(/^## /)) { if (currentBlock !== null) headingBlocks.push(currentBlock); currentBlock = { heading: line, lines: [line] }; } else if (currentBlock !== null) { currentBlock.lines.push(line); } else { intro.push(line); } }
if (currentBlock !== null) headingBlocks.push(currentBlock);
var seenHeadings = {}; var uniqueBlocks = [];
